export const MOVEMENT_PATTERNS = ['Push', 'Pull', 'Squat', 'Hinge', 'Fly', 'Isolation']
export const EQUIPMENT_TYPES = ['Barbell', 'EZ-Bar', 'Dumbbell', 'Cable', 'Machine', 'Bodyweight', 'Smith Machine', 'Kettlebell', 'Trap Bar', 'Landmine', 'Plate']
export const FORCE_VECTORS = ['horizontal', 'vertical', 'diagonal']

export function getAllExercises(customExercises = []) {
  return [...SEED_EXERCISES, ...customExercises]
}

export function getExerciseById(id, customExercises = []) {
  return getAllExercises(customExercises).find(e => e.id === id) || null
}
